class LmdbOmniJoinEstimationGeneratedShapeTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final int TOTAL_STATEMENTS = 1_000_000;
	private static final int LOAD_BATCH_SIZE = 8_192;
	private static final int PATH_ROOTS = 2_000;
	private static final int STAR_CENTERS = 25_000;
	private static final int BRIDGED_STAR_ROWS = 2_500;
	private static final int PARTIAL_STAR_NOISE_CENTERS = 20_000;
	private static final int PATH_NOISE_STATEMENTS = 80_000;
	private static final int BRIDGED_STAR_NOISE_ROWS = 1_500;
	private static final int PREDICATE_FLOOD_STATEMENTS = 16_000;
	private static final int[] PATH_FANOUTS = { 3, 1, 4, 1, 2, 1 };
	private static final int[] STAR_FANOUTS = { 1, 3, 1, 2, 1, 4, 1 };
	private static final int[] FIRST_BRIDGED_STAR_FANOUTS = { 1, 2, 1, 1, 1, 3, 1 };
	private static final int[] SECOND_BRIDGED_STAR_FANOUTS = { 1, 1, 2, 1, 3, 1, 1 };
	private static final int[] THIRD_BRIDGED_STAR_FANOUTS = { 1, 2, 1, 2, 1, 1, 1 };

	@Test
	void omniEstimatesGeneratedShapesAndComparesToLmdbExecution(@TempDir File dataDir) throws Exception {
		GeneratedOmniData data = new GeneratedOmniData();

		LmdbStore store = new LmdbStore(dataDir, lmdbConfig());
		SailRepository repository = new SailRepository(store);
		repository.init();
		try {
			SketchBasedJoinEstimator estimator = store.getBackingStore().getSketchBasedJoinEstimator();
			estimator.configurePersistence(null, false);

			try (SailRepositoryConnection connection = repository.getConnection()) {
				connection.begin(IsolationLevels.NONE);
				assertEquals(TOTAL_STATEMENTS, data.loadInto(connection));
				connection.commit();
			}

			estimator.rebuild();
			LmdbPlannerAwait.awaitSketchesReady(store, Duration.ofMinutes(3));

			List<ShapeResult> results = new ArrayList<>();
			try (SailRepositoryConnection connection = repository.getConnection()) {
				results.add(estimateAndRun(connection, estimator, data.sixHopPath()));
				results.add(estimateAndRun(connection, estimator, data.sevenPointStar()));
				results.add(estimateAndRun(connection, estimator, data.threeBridgedSevenPointStars()));
			}

			results.forEach(result -> System.out.println("LMDB OMNI generated estimate: " + result));

			assertAll(results.stream()
					.map(result -> () -> assertResult(result)));
		} finally {
			try {
				repository.shutDown();
			} finally {
				LmdbTestUtil.deleteDir(dataDir);
			}
		}
	}

	private static LmdbStoreConfig lmdbConfig() {
		return new LmdbStoreConfig("spoc,posc,ospc,psoc")
				.setSketchEstimatorEnabled(true)
				.setSketchEstimatorStrategy("omni")
				.setSketchEstimatorSubjectBucketCount(1024)
				.setSketchEstimatorPredicateBucketCount(128)
				.setSketchEstimatorObjectBucketCount(1024)
				.setSketchEstimatorContextBucketCount(16)
				.setSketchEstimatorThrottleEveryN(1)
				.setSketchEstimatorThrottleMillis(0)
				.setBulkOperationSize(8192)
				.setTripleDBSize(2L * 1024 * 1024 * 1024)
				.setValueDBSize(2L * 1024 * 1024 * 1024);
	}

	private static ShapeResult estimateAndRun(SailRepositoryConnection connection, SketchBasedJoinEstimator estimator,
			GeneratedQuery query) {
		double estimatedRows = estimator.cardinality(statementPatterns(query.sparql()));
		long actualRows = executeRows(connection, query.sparql());
		return new ShapeResult(query.name(), statementPatterns(query.sparql()).size(), estimatedRows, actualRows,
				relativeError(estimatedRows, actualRows), factorError(estimatedRows, actualRows));
	}

	private static void assertResult(ShapeResult result) {
		assertTrue(result.actualRows() > 0L, result::toString);
		assertTrue(Double.isFinite(result.estimatedRows()) && result.estimatedRows() >= 0.0d, result::toString);
		assertTrue(Double.isFinite(result.relativeError()) && result.relativeError() >= 0.0d, result::toString);
		assertTrue(Double.isFinite(result.factorError()) && result.factorError() >= 1.0d, result::toString);
		assertTrue(result.relativeError() <= 0.5d,
				() -> "Expected OMNI estimate within 50% of LMDB actual rows: " + result);
	}

	private static long executeRows(SailRepositoryConnection connection, String sparql) {
		String previousCascadesMode = System.setProperty(LmdbCascadesOptimizer.MODE_PROPERTY, "off");
		try {
			try (TupleQueryResult result = connection.prepareTupleQuery(countQuery(sparql)).evaluate()) {
				if (result.hasNext()) {
					Value count = result.next().getValue("count");
					if (count instanceof Literal literal) {
						return literal.longValue();
					}
				}
			}
		} finally {
			restoreProperty(LmdbCascadesOptimizer.MODE_PROPERTY, previousCascadesMode);
		}
		throw new AssertionError("COUNT query produced no numeric count for: " + sparql);
	}

	private static void restoreProperty(String name, String previousValue) {
		if (previousValue == null) {
			System.clearProperty(name);
		} else {
			System.setProperty(name, previousValue);
		}
	}

	private static String countQuery(String sparql) {
		return "SELECT (COUNT(*) AS ?count) " + sparql.substring(sparql.indexOf("WHERE"));
	}

	private static List<TupleExpr> statementPatterns(String sparql) {
		ParsedTupleQuery parsedQuery = QueryParserUtil.parseTupleQuery(QueryLanguage.SPARQL, sparql, null);
		List<TupleExpr> patterns = new ArrayList<>();
		parsedQuery.getTupleExpr().visit(new AbstractSimpleQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(StatementPattern node) {
				patterns.add(node);
			}
		});
		return List.copyOf(patterns);
	}

	private static double relativeError(double estimatedRows, long actualRows) {
		return Math.abs(estimatedRows - actualRows) / Math.max(1.0d, actualRows);
	}

	private static double factorError(double estimatedRows, long actualRows) {
		double lower = Math.max(1.0d, Math.min(estimatedRows, actualRows));
		double upper = Math.max(estimatedRows, actualRows);
		return upper / lower;
	}

	private static IRI iri(String localName) {
		return VF.createIRI("urn:omni-generated:" + localName);
	}

	private static final class GeneratedOmniData {
		private final IRI[] pathPredicates = predicates("path:p", 6);
		private final IRI[] starPredicates = predicates("star:p", 7);
		private final IRI[] firstStarPredicates = predicates("bridge:first:p", 7);
		private final IRI[] secondStarPredicates = predicates("bridge:second:p", 7);
		private final IRI[] thirdStarPredicates = predicates("bridge:third:p", 7);
		private final IRI bridgeFirstSecond = iri("bridge:first-second");
		private final IRI bridgeSecondThird = iri("bridge:second-third");

		long loadInto(SailRepositoryConnection connection) {
			StatementBatch batch = new StatementBatch(connection);
			addSixHopPaths(batch);
			addSevenPointStars(batch);
			addThreeBridgedSevenPointStars(batch);
			addNoise(batch);
			batch.flush();
			if (batch.count() != TOTAL_STATEMENTS) {
				throw new AssertionError("Expected " + TOTAL_STATEMENTS + " statements, got " + batch.count());
			}
			return batch.count();
		}

		GeneratedQuery sixHopPath() {
			StringBuilder where = new StringBuilder();
			for (int hop = 0; hop < pathPredicates.length; hop++) {
				where.append("?path")
						.append(hop)
						.append(" <")
						.append(pathPredicates[hop].stringValue())
						.append("> ?path")
						.append(hop + 1)
						.append(" .\n");
			}
			return new GeneratedQuery("six-hop path", selectAll(where));
		}

		GeneratedQuery sevenPointStar() {
			return new GeneratedQuery("seven-point star", selectAll(starWhere("starCenter", "starLeaf",
					starPredicates)));
		}

		GeneratedQuery threeBridgedSevenPointStars() {
			StringBuilder where = new StringBuilder();
			where.append(starWhere("bridgeA", "bridgeALeaf", firstStarPredicates));
			where.append("?bridgeA <").append(bridgeFirstSecond.stringValue()).append("> ?bridgeB .\n");
			where.append(starWhere("bridgeB", "bridgeBLeaf", secondStarPredicates));
			where.append("?bridgeB <").append(bridgeSecondThird.stringValue()).append("> ?bridgeC .\n");
			where.append(starWhere("bridgeC", "bridgeCLeaf", thirdStarPredicates));
			return new GeneratedQuery("three bridged seven-point stars", selectAll(where));
		}

		private void addSixHopPaths(StatementBatch batch) {
			List<Resource> subjects = new ArrayList<>(PATH_ROOTS);
			for (int row = 0; row < PATH_ROOTS; row++) {
				subjects.add(pathNode(0, row));
			}
			for (int hop = 0; hop < pathPredicates.length; hop++) {
				List<Resource> nextSubjects = new ArrayList<>(subjects.size() * PATH_FANOUTS[hop]);
				for (int subjectIndex = 0; subjectIndex < subjects.size(); subjectIndex++) {
					Resource subject = subjects.get(subjectIndex);
					for (int edge = 0; edge < PATH_FANOUTS[hop]; edge++) {
						Resource object = pathNode(hop + 1, subjectIndex * PATH_FANOUTS[hop] + edge);
						batch.add(subject, pathPredicates[hop], object);
						nextSubjects.add(object);
					}
				}
				subjects = nextSubjects;
			}
		}

		private void addSevenPointStars(StatementBatch batch) {
			for (int row = 0; row < STAR_CENTERS; row++) {
				addStar(batch, starCenter(row), starPredicates, STAR_FANOUTS, "star:leaf:");
			}
		}

		private void addThreeBridgedSevenPointStars(StatementBatch batch) {
			for (int row = 0; row < BRIDGED_STAR_ROWS; row++) {
				Resource first = iri("bridge:first:center:" + row);
				Resource second = iri("bridge:second:center:" + row);
				Resource third = iri("bridge:third:center:" + row);
				addStar(batch, first, firstStarPredicates, FIRST_BRIDGED_STAR_FANOUTS, "bridge:first:leaf:");
				addStar(batch, second, secondStarPredicates, SECOND_BRIDGED_STAR_FANOUTS, "bridge:second:leaf:");
				addStar(batch, third, thirdStarPredicates, THIRD_BRIDGED_STAR_FANOUTS, "bridge:third:leaf:");
				batch.add(first, bridgeFirstSecond, second);
				batch.add(second, bridgeSecondThird, third);
			}
		}

		private void addNoise(StatementBatch batch) {
			for (int row = 0; row < PARTIAL_STAR_NOISE_CENTERS; row++) {
				addPartialStar(batch, iri("star:partial:" + row), starPredicates, new int[] { 2, 4, 1, 3, 1, 5 },
						"star:partial-leaf:");
			}
			for (int row = 0; row < PATH_NOISE_STATEMENTS; row++) {
				IRI predicate = pathPredicates[row % pathPredicates.length];
				batch.add(iri("noise:path:s:" + row), predicate, iri("noise:path:o:" + (row % 256)));
			}
			for (int row = 0; row < BRIDGED_STAR_NOISE_ROWS; row++) {
				Resource first = iri("bridge:noise:first:" + row);
				Resource second = iri("bridge:noise:second:" + row);
				addStar(batch, first, firstStarPredicates, FIRST_BRIDGED_STAR_FANOUTS, "bridge:noise:first-leaf:");
				addPartialStar(batch, second, secondStarPredicates, new int[] { 1, 1, 2, 1, 1 },
						"bridge:noise:second-leaf:");
				batch.add(first, bridgeFirstSecond, second);
			}
			for (int row = 0; row < PREDICATE_FLOOD_STATEMENTS; row++) {
				IRI predicate = starPredicates[row % starPredicates.length];
				batch.add(iri("noise:flood:s:" + row), predicate, iri("noise:flood:o:" + (row % 1024)));
			}
		}

		private void addStar(StatementBatch batch, Resource center, IRI[] predicates, int[] fanouts,
				String leafPrefix) {
			addPartialStar(batch, center, predicates, fanouts, leafPrefix);
		}

		private void addPartialStar(StatementBatch batch, Resource center, IRI[] predicates, int[] fanouts,
				String leafPrefix) {
			for (int point = 0; point < fanouts.length; point++) {
				for (int edge = 0; edge < fanouts[point]; edge++) {
					batch.add(center, predicates[point], iri(leafPrefix + point + ":" + edge));
				}
			}
		}

		private static String selectAll(CharSequence where) {
			return "SELECT * WHERE {\n" + where + "}";
		}

		private static String starWhere(String center, String leafPrefix, IRI[] predicates) {
			StringBuilder where = new StringBuilder();
			for (int point = 0; point < predicates.length; point++) {
				where.append("?")
						.append(center)
						.append(" <")
						.append(predicates[point].stringValue())
						.append("> ?")
						.append(leafPrefix)
						.append(point)
						.append(" .\n");
			}
			return where.toString();
		}

		private static IRI[] predicates(String prefix, int count) {
			IRI[] predicates = new IRI[count];
			for (int i = 0; i < count; i++) {
				predicates[i] = iri(prefix + i);
			}
			return predicates;
		}

		private static Resource pathNode(int hop, int row) {
			return iri("path:node:" + hop + ":" + row);
		}

		private static Resource starCenter(int row) {
			return iri("star:center:" + row);
		}
	}

	private static final class StatementBatch {
		private final SailRepositoryConnection connection;
		private final List<Statement> statements = new ArrayList<>(LOAD_BATCH_SIZE);
		private long count;

		private StatementBatch(SailRepositoryConnection connection) {
			this.connection = connection;
		}

		private void add(Resource subject, IRI predicate, Value object) {
			statements.add(VF.createStatement(subject, predicate, object));
			count++;
			if (statements.size() == LOAD_BATCH_SIZE) {
				flush();
			}
		}

		private void flush() {
			if (!statements.isEmpty()) {
				connection.add(statements);
				statements.clear();
			}
		}

		private long count() {
			return count;
		}
	}

	private record GeneratedQuery(String name, String sparql) {
	}

	private record ShapeResult(
			String name,
			int patternCount,
			double estimatedRows,
			long actualRows,
			double relativeError,
			double factorError) {
	}
}
